const data = items[0].json.data;
const resultado = [];

const getIdade = (nasc) => {
  const [dia, mes, ano] = nasc.split('/');
  const nascimento = new Date(`${ano}-${mes}-${dia}`);
  const hoje = new Date();
  let idade = hoje.getFullYear() - nascimento.getFullYear();
  const m = hoje.getMonth() - nascimento.getMonth();
  if (m < 0 || (m === 0 && hoje.getDate() < nascimento.getDate())) {
    idade--;
  }
  return idade.toString();
};

// Filtrar contatos com WhatsApp = SIM
const contatosComWhatsApp = data.filter(d => d.WHATSAPP === "SIM");

if (contatosComWhatsApp.length > 0) {
  const pessoa = contatosComWhatsApp[0]; // pega o primeiro com WhatsApp SIM
  const cpf = pessoa.CPFCNPJ;
  const nome = pessoa.NOME;
  const idade = getIdade(pessoa.NASC);

  // Pega até 2 telefones
  const telefones = contatosComWhatsApp.map(d => d.TELEFONE);
  const telefone_1 = telefones[0] || "";
  const telefone_2 = telefones[1] || "";

  resultado.push({
    json: {
      CPF: cpf,
      NOME: nome,
      IDADE: idade,
      TELEFONE_1: telefone_1,
      TELEFONE_2: telefone_2
    }
  });
}

return resultado;

// Entrada: lista de objetos com possíveis duplicações por CPF
const input = items.map(item => item.json);

const merged = {};

for (const obj of input) {
  const cpf = obj.CPF;

  if (!merged[cpf]) {
    merged[cpf] = { ...obj };
  } else {
    // Junta os dados específicos (ex: "Cartão Consignado", "Cartão Benefício")
    for (const key in obj) {
      if (!(key in merged[cpf])) {
        merged[cpf][key] = obj[key];
      }
    }
  }
}

// Converte para formato de saída do n8n
return Object.values(merged).map(data => ({ json: data }));

const rawMessage = items[0].json.message;

// Extrair o JSON que está dentro da string, removendo o prefixo "400 - " e as aspas externas
const regex = /^400 - "(.*)"$/s;
const match = rawMessage.match(regex);

if (!match) {
  throw new Error('Formato inesperado da mensagem');
}

const jsonEscaped = match[1];

// Desescapar as aspas para formar um JSON válido
const jsonString = jsonEscaped.replace(/\\"/g, '"');

const parsed = JSON.parse(jsonString);

// Mensagem de erro geral
const errorMsg = parsed.error;

// Array de margens
const margins = parsed.margins;

// Retornar um array com cada margem + a mensagem de erro
return margins.map(margin => ({
  json: {
    errorMessage: errorMsg,
    nome: margin.nome,
    matricula: margin.numeroMatricula,
    nascimento: margin.nascimento,
    cargo: margin.cargo,
    estavel: margin.estavel_bool,
    tipoProduto: margin.tipoProduto,
    tipoMargem: margin.tipoMargem,
    margemAtual: margin.margem_atual,
    verba: margin.verba,
    folha: margin.folha,
    idProduto: margin.idProduto,
    ocupacao: margin.ocupacao
  }
}));

